// Lookup maps
const cnaeMap = new Map<string, CnaeItem>();
for (const item of CNAES) { cnaeMap.set(item.codigo, item); }

const nbsMap = new Map<string, NbsItem>();
for (const item of NBS_ITEMS) { nbsMap.set(item.codigo, item); }

const lc116Map = new Map<string, Lc116Item>();
for (const item of LC116_ITEMS) { lc116Map.set(item.codigo, item); }

export function getLc116ByCnae(codigoCnae: string): Lc116Item[] {
  const cnae = cnaeMap.get(codigoCnae);
  if (!cnae) return [];
  return cnae.lc116
    .map((code) => lc116Map.get(code))
    .filter((item): item is Lc116Item => item !== undefined);
}

export function getLc116ByNbs(codigoNbs: string): Lc116Item[] {
  const nbs = nbsMap.get(codigoNbs);
  if (!nbs) return [];
  return nbs.lc116
    .map((code) => lc116Map.get(code))
    .filter((item): item is Lc116Item => item !== undefined);
}

export function searchCnae(query: string): CnaeItem[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return CNAES.filter(
    (item) => item.codigo.includes(q) || item.descricao.toLowerCase().includes(q)
  );
}

export function searchNbs(query: string): NbsItem[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return NBS_ITEMS.filter(
    (item) => item.codigo.includes(q) || item.descricao.toLowerCase().includes(q)
  );
}
